import{_ as t,c as r,o as i,al as o}from"./chunks/framework.DM883ANZ.js";const h=JSON.parse('{"title":"MAVLink Developer Guide","description":"MAVLink Developer Guide — MAVLink message, enum and command reference.","frontmatter":{"head":[["meta",{"property":"og:title","content":"MAVLink Developer Guide"}],["meta",{"property":"og:description","content":"MAVLink Developer Guide — MAVLink message, enum and command reference."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://mavlink.io/README.html"}],["link",{"rel":"canonical","href":"https://mavlink.io/README.html"}]]},"headers":[],"relativePath":"README.md","filePath":"README.md","lastUpdated":1784190622000}'),n={name:"README.md"};function a(s,e,l,p,d,m){return i(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="mavlink-developer-guide" tabindex="-1">MAVLink Developer Guide <a class="header-anchor" href="#mavlink-developer-guide" aria-label="Permalink to &quot;MAVLink Developer Guide&quot;">​</a></h1><p>MAVLink is a very lightweight, header-only message marshalling library for micro air vehicles / drones.</p><p>MAVLink follows a modern hybrid publish-subscribe and point-to-point design pattern: Data streams are sent / published as <strong>topics</strong> while configuration sub-protocols such as the <a href="/mission-protocol.html">mission protocol</a> or <a href="/parameter-protocol.html">parameter protocol</a> are point-to-point with retransmission.</p><blockquote><p><strong>Tip</strong> Because MAVLink doesn&#39;t require any additional framing it is very well suited for applications with very limited communication bandwidth. It&#39;s reference implementation in C is highly optimized for resource-constrained systems with limited RAM and flash memory. It is field-proven and deployed in many products where it serves as interoperability interface between components of different manufacturers.</p></blockquote><p>MAVLink was first released early 2009 by Lorenz Meier and has now a <a href="https://github.com/mavlink/mavlink/graphs/contributors" target="_blank" rel="noreferrer">significant number of contributors</a>.</p><p>The content of this book is CC-BY 4.0 licensed.</p>',6)])])}const u=t(n,[["render",a]]);export{h as __pageData,u as default};
